code = """import json

# Load data from stored files
with open('var_functions.query_db:60', 'r') as f:
    fema_funding = json.load(f)

# Initialize results list
results = []

# Process each FEMA project
for item in fema_funding:
    proj_name = item['Project_Name']
    funding = item['Funding_Source']
    amount = int(item['Amount'])
    
    # Add to results with default status (will be enhanced if we find civic docs)
    results.append({
        'project': proj_name,
        'funding': funding,
        'amount': amount,
        'status': 'not started',
        'topics': 'FEMA',
        'type': 'disaster'
    })

# Format output
output_lines = []
for r in results:
    output_lines.append('Project: ' + r['project'])
    output_lines.append('  Funding Source: ' + r['funding'])
    output_lines.append('  Amount: $' + str(r['amount']))
    output_lines.append('  Status: ' + r['status'])
    output_lines.append('  Topics: ' + r['topics'])
    output_lines.append('  Type: ' + r['type'])
    output_lines.append('')

final_output = '\n'.join(output_lines)

print('__RESULT__:')
print(final_output)"""

